const crypto = require('crypto');
const webhookBody = $('Webhook Trigger').first().json.body;
const headers = $('Webhook Trigger').first().json.headers;
const secret = $('Workflow Constants').first().json.N8N_SHARED_SECRET;

const signature = headers['x-profunda-signature'];
if (!signature) throw new Error('Missing x-profunda-signature header');
if (!webhookBody || typeof webhookBody !== 'object') throw new Error('Missing or invalid webhook body');
if (webhookBody.workflow_key !== 'recommendations_generate') throw new Error('workflow_key must be recommendations_generate');
if (!webhookBody.run_id) throw new Error('Missing run_id');

const bodyStr = JSON.stringify(webhookBody);
const hmac = crypto.createHmac('sha256', secret).update(bodyStr).digest('hex');
if (hmac !== signature) throw new Error('Invalid HMAC signature');

return [{ json: webhookBody }];

const input = $('Verify Signature').first().json;
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!input.metro_id || typeof input.metro_id !== 'string' || !UUID_RE.test(input.metro_id)) {
  throw new Error('metro_id must be a valid UUID');
}

const horizon_days = (typeof input.horizon_days === 'number' && input.horizon_days > 0) ? Math.min(input.horizon_days, 365) : 30;
const opportunities = Array.isArray(input.opportunities) ? input.opportunities.slice(0, 30) : [];
const recent_signals = Array.isArray(input.recent_signals) ? input.recent_signals.slice(0, 50) : [];
const org_facts = Array.isArray(input.org_facts) ? input.org_facts.slice(0, 50) : [];
const watchlist_signals = Array.isArray(input.watchlist_signals) ? input.watchlist_signals.slice(0, 50) : [];

return [{
  json: {
    run_id: input.run_id,
    workflow_key: 'recommendations_generate',
    metro_id: input.metro_id,
    horizon_days,
    opportunities,
    recent_signals,
    org_facts,
    watchlist_signals
  }
}];

const v = $('Validate Input').first().json;

// Build context for LLM
const oppSummary = v.opportunities.map((o, i) => `${i+1}. ${o.org_name || 'Unknown Org'} (stage: ${o.stage || 'unknown'})`).join('
');
const signalSummary = v.recent_signals.map(s => `- ${s.signal_type || s.type}: ${s.summary || s.signal_value || ''}`).join('
');
const factSummary = v.org_facts.map(f => `- ${f.org_name || ''}: ${f.fact || f.summary || ''}`).join('
');
const watchlistSummary = v.watchlist_signals.map(w => `- ${w.org_name || ''}: ${w.signal_type || ''} - ${w.summary || ''}`).join('
');

const context = `Metro Opportunities (${v.opportunities.length}):
${oppSummary || 'None'}

Recent Signals (${v.recent_signals.length}):
${signalSummary || 'None'}

Org Facts (${v.org_facts.length}):
${factSummary || 'None'}

Watchlist Signals (${v.watchlist_signals.length}):
${watchlistSummary || 'None'}

Horizon: ${v.horizon_days} days`;

return [{ json: { run_id: v.run_id, metro_id: v.metro_id, context, horizon_days: v.horizon_days } }];

