const ctx = $('Build Context').first().json;
let txt = '';
try { txt = $('LLM Generate Recommendations').first().json?.choices?.[0]?.message?.content || ''; } catch(e) { txt = ''; }

let recommendations = [];
try {
  const parsed = JSON.parse(txt);
  recommendations = Array.isArray(parsed.recommendations) ? parsed.recommendations.slice(0, 5) : [];
} catch(e) {
  recommendations = [];
}

// Clean each recommendation
const cleaned = recommendations.map(r => ({
  title: String(r.title || '').slice(0, 200),
  body: String(r.body || '').slice(0, 1000),
  priority: ['high','medium','low'].includes(r.priority) ? r.priority : 'medium',
  recommendation_type: ['check_in','deepen','introduce','research'].includes(r.recommendation_type) ? r.recommendation_type : 'check_in',
  opportunity_ids: Array.isArray(r.opportunity_ids) ? r.opportunity_ids : []
}));

return [{
  json: {
    run_id: ctx.run_id,
    workflow_key: 'recommendations_generate',
    payload: {
      result: { metro_id: ctx.metro_id, recommendations: cleaned, recommendation_count: cleaned.length, horizon_days: ctx.horizon_days },
      error: null,
      failed_node: null
    }
  }
}];
